function loadFiles(){fetch("/api/files").then(e=>e.json()).then(e=>{const t=e.filter(e=>"config.cfg"!==e.name);displayFiles(t),fetch("/api/storage").then(e=>e.json()).then(e=>{updateStorageInfo(e)}).catch(e=>{console.error("Error fetching storage info:",e)})}).catch(e=>{showMessage("Error loading files: "+e.message,!1)})}function displayFiles(e){const t=document.getElementById("fileList");if(0===e.length)return void(t.innerHTML='<tr><td colspan="3">No files found</td></tr>');const n=e.sort((e,t)=>e.name.localeCompare(t.name));let o="";n.forEach(e=>{o+="<tr>",o+=`<td>${e.name}</td>`,o+=`<td>${formatSize(e.size)}</td>`,o+="<td>",o+=`<a href='/api/files/download?filename=${encodeURIComponent(e.name)}' class='button download'>Download</a>`,o+=`<button type="button" onclick='deleteFile("${e.name}")' class='button delete'>Delete</button>`,o+="</td>",o+="</tr>"}),t.innerHTML=o}function updateStorageInfo(e){document.getElementById("usedSpace").textContent=formatSizeWithUnit(e.usedBytes),document.getElementById("totalSpace").textContent=formatSizeWithUnit(e.totalBytes),document.getElementById("freeSpace").textContent=formatSizeWithUnit(e.freeBytes),document.getElementById("percentUsed").textContent=e.percentUsed+"%",document.getElementById("progressFill").style.width=e.percentUsed+"%"}function deleteFile(e){confirm(`Are you sure you want to delete ${e}?`)&&fetch("/api/files/delete",{method:"POST",headers:{"Content-Type":"application/x-www-form-urlencoded"},body:"filename="+encodeURIComponent(e)}).then(e=>e.text()).then(e=>{showMessage(e,!0),loadFiles()}).catch(e=>{showMessage(e.message,!1)})}function showMessage(e,t){const n=document.getElementById("messageArea");n.innerHTML=`<div class='message ${t?"success":"error"}'>${e}</div>`,setTimeout(()=>{n.innerHTML=""},5e3)}loadFiles();